// Package resource provides a representation of computing resources used in Kubernetes.
package resource

import (
	"errors"
	"fmt"
	"math/big"
	"regexp"
	"strings"

	flag "github.com/spf13/pflag"
	"speter.net/go/exp/math/dec/inf"
)

// Quantity is a fixed-point representation of a number.
// It provides convenient marshaling/unmarshaling in JSON and YAML,
// in addition to String() and Int64() accessors.
//
// The serialization format is:
//
// <quantity>        ::= <signedNumber><suffix>
//   (Note that <suffix> may be empty, from the "" case in <decimalSI>.)
// <digit>           ::= 0 | 1 | ... | 9
// <digits>          ::= <digit> | <digit><digits>
// <number>          ::= <digits> | <digits>.<digits> | <digits>. | .<digits>
// <sign>            ::= "+" | "-"
// <signedNumber>    ::= <number> | <sign><number>
// <suffix>          ::= <binarySI> | <decimalExponent> | <decimalSI>
// <binarySI>        ::= Ki | Mi | Gi | Ti | Pi | Ei
//   (International System of units; See: http://physics.nist.gov/cuu/Units/binary.html)
// <decimalSI>       ::= m | "" | k | M | G | T | P | E
//   (Note that 1024 = 1Ki but 1000 = 1k; I didn't choose the capitalization.)
// <decimalExponent> ::= "e" <signedNumber> | "E" <signedNumber>
//
// No matter which of the three exponent forms is used, no quantity may represent
// a number greater than 2^63-1 in magnitude, nor may it have more than 3 decimal
// places. Numbers larger or more precise will be capped or rounded up.
// (E.g.: 0.1m will rounded up to 1m.)
// This may be extended in the future if we require larger or smaller quantities.
//
// When a Quantity is parsed from a string, it will remember the type of suffix
// it had, and will use the same type again when it is serialized.
//
// Before serializing, Quantity will be put in "canonical form".
// This means that Exponent/suffix will be adjusted up or down (with a
// corresponding increase or decrease in Mantissa) such that:
//   a. No precision is lost
//   b. No fractional digits will be emitted
//   c. The exponent (or suffix) is as large as possible.
// The sign will be omitted unless the number is negative.
//
// Examples:
//   1.5 will be serialized as "1500m"
//   1.5Gi will be serialized as "1536Mi"
//
// NOTE: We reserve the right to amend this canonical format, perhaps to
//   allow 1.5 to be canonical.
// TODO: Remove above disclaimer after all bikeshedding about format is over,
//   or after March 2015.
//
// Note that the quantity will NEVER be internally represented by a
// floating point number. That is the whole point of this exercise.
//
// Non-canonical values will still parse as long as they are well formed,
// but will be re-emitted in their canonical form. (So always use canonical
// form, or don't diff.)
//
// This format is intended to make it difficult to use these numbers without
// writing some sort of special handling code in the hopes that that will
// cause implementors to also use a fixed point implementation.
//
// +protobuf=true
// +protobuf.embed=QuantityProto
// +protobuf.options.marshal=false
// +protobuf.options.(gogoproto.goproto_stringer)=false
type Quantity struct {
	// Amount is a fixed-point representation of the number.
	// It is public so clients can manipulate it directly if the provided
	// methods are not sufficient.
	Amount *inf.Dec

	// Format keeps track of the original format of the quantity, so it can be
	// serialized back to the same format.
	Format
}

// Format lists the three possible formattings of a quantity.
type Format string

const (
	// DecimalExponent formats numbers using an exponent, e.g., 12e6.
	DecimalExponent = Format("DecimalExponent")
	// BinarySI formats numbers using binary SI units, e.g., 12Mi (12 * 2^20).
	BinarySI        = Format("BinarySI")
	// DecimalSI formats numbers using decimal SI units, e.g., 12M (12 * 10^6).
	DecimalSI       = Format("DecimalSI")
)

// MustParse turns the given string into a quantity or panics.
// It is intended for cases where the input string is known to be valid.
func MustParse(str string) Quantity {
	q, err := ParseQuantity(str)
	if err != nil {
		panic(fmt.Errorf("cannot parse '%v': %v", str, err))
	}
	return *q
}

// Scale is a scaling factor for quantities. It is used for getting and
// setting the base-10 scaled value of a quantity.
type Scale int

// These constants are used for scaling numbers. For example, to get the value
// of a quantity in megabytes, you would use the Mega constant.
const (
	Nano  Scale = -9
	Micro Scale = -6
	Milli Scale = -3
	Kilo  Scale = 3
	Mega  Scale = 6
	Giga  Scale = 9
	Tera  Scale = 12
	Peta  Scale = 15
	Exa   Scale = 18
)

const (
	// splitREString is the regular expression used to split a quantity string
	// into its numeric and suffix parts.
	splitREString = "^([+-]?[0-9.]+)([eEinumkKMGTP]*[-+]?[0-9]*)$"
)

var (
	// splitRE is the compiled regular expression for splitting quantity strings.
	splitRE = regexp.MustCompile(splitREString)

	// Pre-defined errors for parsing failures.
	ErrFormatWrong = errors.New("quantities must match the regular expression '" + splitREString + "'")
	ErrNumeric     = errors.New("unable to parse numeric part of quantity")
	ErrSuffix      = errors.New("unable to parse quantity's suffix")

	// Commonly used big.Int values, defined as read-only constants for efficiency.
	bigTen      = big.NewInt(10)
	bigZero     = big.NewInt(0)
	bigOne      = big.NewInt(1)
	bigThousand = big.NewInt(1000)
	big1024     = big.NewInt(1024)

	// Commonly used inf.Dec values, defined as read-only constants for efficiency.
	decZero      = inf.NewDec(0, 0)
	decOne       = inf.NewDec(1, 0)
	decMinusOne  = inf.NewDec(-1, 0)
	decThousand  = inf.NewDec(1000, 0)
	dec1024      = inf.NewDec(1024, 0)
	decMinus1024 = inf.NewDec(-1024, 0)

	// maxAllowed is the largest number a Quantity can represent, equivalent to max int64.
	maxAllowed = inf.NewDec((1<<63)-1, 0)

	// MaxMilliValue is the maximum value that can be represented in milli-units without overflow.
	MaxMilliValue = int64(((1 << 63) - 1) / 1000)
)

// ParseQuantity turns a string representation of a quantity into a Quantity object.
func ParseQuantity(str string) (*Quantity, error) {
	// First, split the string into its numeric and suffix parts.
	parts := splitRE.FindStringSubmatch(strings.TrimSpace(str))
	if len(parts) != 3 {
		return nil, ErrFormatWrong
	}

	// Create a new decimal and parse the numeric part.
	amount := new(inf.Dec)
	if _, ok := amount.SetString(parts[1]); !ok {
		return nil, ErrNumeric
	}

	// Interpret the suffix to determine the base and exponent.
	base, exponent, format, ok := quantitySuffixer.interpret(suffix(parts[2]))
	if !ok {
		return nil, ErrSuffix
	}

	// Apply the scaling factor from the suffix to the amount.
	if base == 10 {
		amount.SetScale(amount.Scale() + Scale(exponent).infScale())
	} else if base == 2 {
		numericSuffix := big.NewInt(1).Lsh(bigOne, uint(exponent))
		ub := amount.UnscaledBig()
		amount.SetUnscaledBig(ub.Mul(ub, numericSuffix))
	}

	// Ensure the quantity is within the allowed bounds and precision.
	// We handle positive and negative numbers separately.
	sign := amount.Sign()
	if sign == -1 {
		amount.Neg(amount)
	}

	// Round up small non-zero values to the minimum precision (nano).
	// This ensures that a request for a small but non-zero resource
	// is not rounded down to zero.
	if v, ok := amount.Unscaled(); v != int64(0) || !ok {
		amount.Round(amount, Nano.infScale(), inf.RoundUp)
	}

	// Cap the value at the maximum allowed magnitude.
	if amount.Cmp(maxAllowed) > 0 {
		amount.Set(maxAllowed)
	}

	// For binary SI units, if the value is between -1 and 1 (exclusive of 0),
	// switch to decimal SI format to avoid rounding and confusion.
	if format == BinarySI && amount.Cmp(decOne) < 0 && amount.Cmp(decZero) > 0 {
		format = DecimalSI
	}
	if sign == -1 {
		amount.Neg(amount)
	}

	return &Quantity{amount, format}, nil
}

// removeFactors repeatedly divides d by factor, returning the remainder
// and the number of times division was performed. This is used to extract
// a power-of-N component from a number.
func removeFactors(d, factor *big.Int) (result *big.Int, times int) {
	q := big.NewInt(0)
	m := big.NewInt(0)
	for d.Cmp(bigZero) != 0 {
		q.DivMod(d, factor, m)
		if m.Cmp(bigZero) != 0 {
			break
		}
		times++
		d, q = q, d
	}
	return d, times
}

// Canonicalize converts a Quantity to its canonical string representation,
// which includes a numeric part and a suffix.
func (q *Quantity) Canonicalize() (string, suffix) {
	if q.Amount == nil || q.Amount.Cmp(&inf.Dec{}) == 0 {
		return "0", ""
	}

	// Determine the appropriate format for serialization.
	format := q.Format
	switch format {
	case DecimalExponent, DecimalSI:
		// Use decimal SI by default.
	case BinarySI:
		// For values between -1024 and 1024, use decimal SI to avoid rounding.
		if q.Amount.Cmp(decMinus1024) > 0 && q.Amount.Cmp(dec1024) < 0 {
			format = DecimalSI
		} else {
			// If binary SI would cause rounding, fall back to decimal SI.
			tmp := &inf.Dec{}
			tmp.Round(q.Amount, 0, inf.RoundUp)
			if tmp.Cmp(q.Amount) != 0 {
				format = DecimalSI
			}
		}
	default:
		// Fallback to exponent format.
		format = DecimalExponent
	}

	switch format {
	case DecimalExponent, DecimalSI:
		mantissa := q.Amount.UnscaledBig()
		exponent := int(-q.Amount.Scale())
		amount := big.NewInt(0).Set(mantissa)

		// Normalize by extracting all factors of 10 into the exponent.
		amount, times := removeFactors(amount, bigTen)
		exponent += times

		// Adjust the exponent to be a multiple of 3 for standard SI prefixes.
		for exponent%3 != 0 {
			amount.Mul(amount, bigTen)
			exponent--
		}

		// Construct the suffix from the final exponent and format.
		suffix, _ := quantitySuffixer.construct(10, exponent, format)
		number := amount.String()
		return number, suffix
	case BinarySI:
		// Round up to the nearest integer for binary SI representation.
		tmp := &inf.Dec{}
		tmp.Round(q.Amount, 0, inf.RoundUp)

		// Extract factors of 1024 to determine the binary SI prefix.
		amount, exponent := removeFactors(tmp.UnscaledBig(), big1024)
		suffix, _ := quantitySuffixer.construct(2, exponent*10, format)
		number := amount.String()
		return number, suffix
	}
	return "0", ""
}

// String formats the Quantity as a string in its canonical form.
func (q *Quantity) String() string {
	number, suffix := q.Canonicalize()
	return number + string(suffix)
}

// Cmp compares q and y and returns:
//
//   -1 if q <  y
//    0 if q == y
//   +1 if q >  y
//
func (q *Quantity) Cmp(y Quantity) int {
	if q.Amount == nil {
		if y.Amount == nil {
			return 0
		}
		return -y.Amount.Sign()
	}
	if y.Amount == nil {
		return q.Amount.Sign()
	}
	return q.Amount.Cmp(y.Amount)
}

// Add adds y to q.
func (q *Quantity) Add(y Quantity) error {
	if y.Amount == nil {
		return nil
	}
	if q.Amount == nil {
		q.Amount = &inf.Dec{}
	}
	// Preserve the format of the non-zero value when adding to a zero value.
	zero := &inf.Dec{}
	if q.Amount.Cmp(zero) == 0 && y.Amount.Cmp(zero) != 0 {
		q.Format = y.Format
	}
	q.Amount.Add(q.Amount, y.Amount)
	return nil
}

// Sub subtracts y from q.
func (q *Quantity) Sub(y Quantity) error {
	if y.Amount == nil {
		return nil
	}
	if q.Amount == nil {
		q.Amount = &inf.Dec{}
	}
	// Preserve the format of the non-zero value when subtracting from a zero value.
	zero := &inf.Dec{}
	if q.Amount.Cmp(zero) == 0 && y.Amount.Cmp(zero) != 0 {
		q.Format = y.Format
	}
	q.Amount.Sub(q.Amount, y.Amount)
	return nil
}

// Neg sets q to -y.
func (q *Quantity) Neg(y Quantity) error {
	if y.Amount == nil {
		*q = y
		return nil
	}
	if q.Amount == nil {
		q.Amount = &inf.Dec{}
	}
	q.Amount.Neg(y.Amount)
	q.Format = y.Format
	return nil
}

// MarshalJSON implements the json.Marshaler interface.
func (q Quantity) MarshalJSON() ([]byte, error) {
	return []byte(`"` + q.String() + `"`), nil
}

// UnmarshalJSON implements the json.Unmarshaler interface.
func (q *Quantity) UnmarshalJSON(value []byte) error {
	str := string(value)
	// After unmarshaling, the quantity is guaranteed to be in canonical form.
	parsed, err := ParseQuantity(strings.Trim(str, `"`))
	if err != nil {
		return err
	}
	*q = *parsed
	return nil
}

// NewQuantity returns a new Quantity representing the given value.
func NewQuantity(value int64, format Format) *Quantity {
	return &Quantity{
		Amount: inf.NewDec(value, 0),
		Format: format,
	}
}

// NewMilliQuantity returns a new Quantity representing the given value in milli-units.
func NewMilliQuantity(value int64, format Format) *Quantity {
	return &Quantity{
		Amount: inf.NewDec(value, 3),
		Format: format,
	}
}

// NewScaledQuantity returns a new Quantity representing the given value with the specified scale.
func NewScaledQuantity(value int64, scale Scale) *Quantity {
	return &Quantity{
		Amount: inf.NewDec(value, scale.infScale()),
		Format: DecimalSI,
	}
}

// Value returns the integer value of q, discarding any fractional part.
func (q *Quantity) Value() int64 {
	if q.Amount == nil {
		return 0
	}
	v, _ := q.Amount.Unscaled().Int64()
	return v
}

// MilliValue returns the value of q in milli-units, rounded up.
// It may overflow; call Value() first to check magnitude.
func (q *Quantity) MilliValue() int64 {
	return q.ScaledValue(Milli)
}

// ScaledValue returns the value of q scaled by 10^scale, rounded up.
// It may overflow; call Value() first to check magnitude.
// Note: The implementation of `scaledValue` is not in this file.
func (q *Quantity) ScaledValue(scale Scale) int64 {
	if q.Amount == nil {
		return 0
	}
	return scaledValue(q.Amount.UnscaledBig(), int(q.Amount.Scale()), int(scale.infScale()))
}

// Set sets the value of q to the given integer.
func (q *Quantity) Set(value int64) {
	q.SetScaled(value, 0)
}

// SetMilli sets the value of q to the given value in milli-units.
func (q *Quantity) SetMilli(value int64) {
	q.SetScaled(value, Milli)
}

// SetScaled sets the value of q to the given value with the specified scale.
func (q *Quantity) SetScaled(value int64, scale Scale) {
	if q.Amount == nil {
		q.Amount = &inf.Dec{}
	}
	q.Amount.SetUnscaled(value)
	q.Amount.SetScale(scale.infScale())
}

// Copy returns a deep copy of the Quantity. This is important because
// Quantities are mutable, and a shallow copy would share the same underlying
// Amount pointer.
func (q *Quantity) Copy() *Quantity {
	if q.Amount == nil {
		return NewQuantity(0, q.Format)
	}
	tmp := &inf.Dec{}
	return &Quantity{
		Amount: tmp.Set(q.Amount),
		Format: q.Format,
	}
}

// qFlag is a helper type for implementing the pflag.Value interface.
type qFlag struct {
	dest *Quantity
}

// Set implements the pflag.Value interface for Quantity.
func (qf qFlag) Set(val string) error {
	q, err := ParseQuantity(val)
	if err != nil {
		return err
	}
	*qf.dest = *q
	return nil
}

// String implements the pflag.Value interface for Quantity.
func (qf qFlag) String() string {
	return qf.dest.String()
}

// Type implements the pflag.Value interface for Quantity.
func (qf qFlag) Type() string {
	return "quantity"
}

// QuantityFlag defines a Quantity flag with the specified name, default value, and usage string.
func QuantityFlag(flagName, defaultValue, description string) *Quantity {
	q := MustParse(defaultValue)
	flag.Var(NewQuantityFlagValue(&q), flagName, description)
	return &q
}

// NewQuantityFlagValue returns a pflag.Value that can be used to bind a flag to a Quantity variable.
func NewQuantityFlagValue(q *Quantity) flag.Value {
	return qFlag{q}
}

// infScale converts a resource.Scale to an inf.Scale.
func (s Scale) infScale() inf.Scale {
	return inf.Scale(-s)
}
